// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// RJ - PSD - STRY0063760 - The Process needs to set the Shared settings based on the values from the Task
	// changed the when to run to before insert
	// set value of shared folder so documents are correctly copied
	// RJ - PSD - STRY0063760 - now copy attachments from the top task to process
	// Create Top Tasker Definition Record
	var recTaskDef = new GlideRecord('x_153465_discovert_route_tasks');
	var objDuration;
	if (!current.original_tasker_saved_to_process.nil()){
		var grTopTask = new GlideRecord('x_153465_discovert_route_task_instance');
		if(grTopTask.get(current.getValue("original_tasker_saved_to_process"))){
			current.u_shared_attachments = grTopTask.u_shared_attachments;
			current.u_shared_documents = grTopTask.u_shared_documents;
			// STRY0065506 - added  fields added to the Template for parity
			current.u_assigned_member = grTopTask.assigned_to;
			current.classification = grTopTask.classification;
			current.description = grTopTask.instructions;
			current.u_objective = grTopTask.u_objective;
			current.u_primary_assignee = grTopTask.primary_assignee;
			current.u_primary_office = grTopTask.primary_office;
			current.u_restricted_group = grTopTask.assignment_group;
			current.short_description = grTopTask.short_description;
			current.u_tasking_authority = grTopTask.tasking_authority;
			// STRY0075898
			current.u_external_ou = grTopTask.u_external_ou;
			current.poc_name = grTopTask.poc_name;
			current.outbound = grTopTask.outbound;
			current.u_internal_contact = grTopTask.u_internal_contact;
			current.u_internal_contact_performing_task = grTopTask.u_internal_contact_performing_task;

			// STRY0085029 
			current.u_tasker_type = grTopTask.tasker_type;
			current.u_signature_instructions = grTopTask.u_signature_instructions;
			current.u_reviewer = grTopTask.u_reviewer;
			current.provide_response = grTopTask.provide_response;
			current.u_on_behalf_of = grTopTask.on_behalf_of;

			// STRY0076904
			current.u_warning_days = grTopTask.warning_hours;
			current.u_duration = grTopTask.calendar_duration;

			objDuration = new TaskTemplateHelpers().getDurationDaysAndTimeDue(current, current.getValue('u_duration'));
			if(objDuration.u_duration_days > 0){
				current.u_duration_days = objDuration.u_duration_days;
			}
			if(objDuration.u_duration_time_due > 0){
				current.u_duration_time_due.setDateNumericValue(parseInt(objDuration.u_duration_time_due));
			}

			current.u_wait_for_subtasks_to_finish = grTopTask.u_wait_for_subtasks_to_finish;

			// STRY0118875
			recTaskDef.initialize();
			// set the process definition for the Tasker Def
			recTaskDef.tasker_process_definition = current.sys_id;
			recTaskDef.original_tasker_inst = current.original_tasker_saved_to_process;
			recTaskDef.insert();

			// Set the Top Task on the Template
			current.parent_task_def = recTaskDef.sys_id;
			// STRY0084599 - Need a way for deliver and customers to better synchronize field updates and changes
			current = new CustomTaskerFieldHelper().mapFieldDataOnAction('templateCreateFromTaskSaveCopyFromTopTask', grTopTask, current);
		}
	} else {
		recTaskDef.initialize();
		// STRY0084986
		recTaskDef.tasker_type = current.u_tasker_type;
		recTaskDef.u_signature_instructions = current.u_signature_instructions;
		recTaskDef.u_reviewer = current.u_reviewer;
		recTaskDef.provide_response = current.provide_response;
		recTaskDef.u_on_behalf_of = current.u_on_behalf_of;
		// set the process definition for the Tasker Def
		recTaskDef.tasker_process_definition = current.sys_id;
		recTaskDef.short_description = current.short_description;
		recTaskDef.instructions = current.description;
		recTaskDef.route_order = 1;

		// STRY0065506 - added these fields when brinign task Parity to template
		recTaskDef.u_objective = current.u_objective;
		recTaskDef.classification = current.classification;
		recTaskDef.primary_assignee = current.u_primary_assignee;
		recTaskDef.primary_office = current.u_primary_office;
		recTaskDef.assigned_to_group = current.u_restricted_group;
		recTaskDef.tasking_authority = current.u_tasking_authority;
		recTaskDef.assigned_to_individual = current.u_assigned_member;
		// STRY0063652 - pass all of the multi create fields from the Template to the Top Template Task
		recTaskDef.u_create_multiple_subtasks = current.u_create_multiple_subtasks;
		recTaskDef.u_create_subtasks_in_serial = current.u_create_subtasks_in_serial;
		recTaskDef.u_subtask_assigned_member_s = current.u_subtask_assigned_member_s;
		recTaskDef.u_subtask_primary_assignee_s = current.u_subtask_primary_assignee_s;

		// STRY0075898
		recTaskDef.u_external_ou = current.u_external_ou;
		recTaskDef.poc_name = current.poc_name;
		recTaskDef.outbound = current.outbound;
		recTaskDef.u_internal_contact = current.u_internal_contact;
		recTaskDef.u_internal_contact_performing_task = current.u_internal_contact_performing_task;

		// STRY0076904, STRY0091703 corrected as these were flipped.  There is no transation.  We need to correct this eventually.
		recTaskDef.warning_hours = current.u_warning_days;
		recTaskDef.duration = current.u_duration;

		objDuration = new TaskTemplateHelpers().getDurationDaysAndTimeDue(current, current.getValue('u_duration'));
		if(current.u_duration_days){
			recTaskDef.u_duration_days = current.u_duration_days;
		} else {
			recTaskDef.u_duration_days = objDuration.u_duration_days;
		}
		if(current.u_duration_time_due){
			recTaskDef.u_duration_time_due = current.u_duration_time_due;
		} else {
			recTaskDef.u_duration_time_due.setDateNumericValue(objDuration.u_duration_time_due);
		}


		recTaskDef.u_wait_for_subtasks_to_finish = current.u_wait_for_subtasks_to_finish;

		// STRY0084599 - Need a way for deliver and customers to better synchronize field updates and changes
		recTaskDef = new CustomTaskerFieldHelper().mapFieldDataOnAction('templateCreateAddTopTaskTemplate', current, recTaskDef);

		recTaskDef.insert();
		// RJ - PSD - STRY0063760 - The Top Task My Copy to the Top Task Def My will be done on the insert of the my.  All Document Copies are moved into separate scripts
		//GlideSysAttachment.copy('x_153465_discovert_route_task_instance', current.getValue("original_tasker_saved_to_process"), 'x_153465_discovert_route_tasks', recTaskDef.sys_id);

		// Set the Top Task on the Template, must be done after creating the Template Task
		// move this to after insert
		current.parent_task_def = recTaskDef.sys_id;
	}
})(current, previous);
